from collections import Counter
import heapq

class Solution:
    def minimumDeletions(self, word: str, k: int) -> int:
        freq = list(Counter(word).values())
        freq.sort()
        n = len(freq)
        min_deletions = float('inf')

        # Try each frequency as the base
        for i in range(n):
            base = freq[i]
            current_deletions = 0
            for j in range(n):
                if j == i:
                    continue
                if freq[j] < base:
                    current_deletions += freq[j]
                elif freq[j] - base > k:
                    current_deletions += freq[j] - base
            min_deletions = min(min_deletions, current_deletions)

        return min_deletions
